import { useEffect, useState } from "react";

const App = () => {
  const [questions, setQuestions] = useState([]);
  const [selected, setSelected] = useState({});
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    // Simulated fetch - replace with your "http://localhost:3000/api/quiz"
    setQuestions([
      { id: 1, question: "What is the primary use of a mmWave Radar sensor?", options: ["Measuring Humidity", "Detecting Stationary Presence", "Calculating Soil pH", "Measuring Wind Speed"] },
      { id: 2, question: "Which protocol is commonly used for Digital Light Sensors?", options: ["I2C", "SATA", "MIDI", "POP3"] },
      { id: 3, question: "What does an LDR measure?", options: ["Moisture", "Light Intensity", "Gas Levels", "Atmospheric Pressure"] }
    ]);
  }, []);

  const handleSelect = (qid, opt) => {
    setSelected((prev) => ({ ...prev, [qid]: opt }));
  };

  const progress = questions.length > 0 
    ? Math.round(((currentIndex + 1) / questions.length) * 100) 
    : 0;

  const currentQ = questions[currentIndex];

  if (!currentQ) return <div style={styles.container}>Loading...</div>;

  return (
    <div style={styles.container}>
      {/* Background Orbs */}
      <div style={styles.blob1}></div>
      <div style={styles.blob2}></div>

      <div style={styles.wrapper}>
        {/* HEADER */}
        <header style={styles.header}>
          <div>
            <h1 style={styles.title}>Quizzly <span style={styles.versionTag}>v1</span></h1>
            <p style={styles.subtitle}>Harshith B • 23MIS0012</p>
          </div>
          <div style={styles.counter}>
             Question {currentIndex + 1} of {questions.length}
          </div>
        </header>

        {/* PROGRESS BAR */}
        <div style={styles.progressBarBg}>
          <div style={{ ...styles.progressBarFill, width: `${progress}%` }}></div>
        </div>

        {/* QUESTION CARD */}
        <main style={styles.card}>
          <div style={styles.questionSection}>
            <span style={styles.badge}>Question {currentQ.id}</span>
            <h2 style={styles.questionText}>{currentQ.question}</h2>
          </div>

          <div style={styles.optionsGrid}>
            {currentQ.options.map((opt) => {
              const isSelected = selected[currentQ.id] === opt;
              return (
                <button
                  key={opt}
                  onClick={() => handleSelect(currentQ.id, opt)}
                  style={{
                    ...styles.optionBtn,
                    ...(isSelected ? styles.optionSelected : {}),
                  }}
                >
                  <div style={{
                    ...styles.radio,
                    borderColor: isSelected ? "#6366f1" : "rgba(255,255,255,0.2)"
                  }}>
                    {isSelected && <div style={styles.radioInner}></div>}
                  </div>
                  {opt}
                </button>
              );
            })}
          </div>
        </main>

        {/* NAVIGATION CONTROLS */}
        <footer style={styles.footer}>
          <button 
            disabled={currentIndex === 0}
            onClick={() => setCurrentIndex(v => v - 1)}
            style={{...styles.navBtn, opacity: currentIndex === 0 ? 0.4 : 1}}
          >
            Previous
          </button>

          <button 
            onClick={() => {
              if (currentIndex < questions.length - 1) {
                setCurrentIndex(v => v + 1);
              } else {
                alert("Exam Submitted!");
              }
            }}
            style={styles.nextBtn}
          >
            {currentIndex === questions.length - 1 ? "Finish Exam" : "Save & Next"}
          </button>
        </footer>
      </div>
    </div>
  );
};

const styles = {
  container: {
    height: "100vh",
    width: "100vw",
    backgroundColor: "#0b0f1a",
    color: "#f8fafc",
    fontFamily: "'Inter', sans-serif",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    overflow: "hidden",
    position: "relative",
  },
  wrapper: {
    width: "100%",
    maxWidth: "800px",
    padding: "0 20px",
    zIndex: 10,
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "flex-end",
    marginBottom: "20px",
  },
  title: { fontSize: "24px", fontWeight: "800", margin: 0 },
  versionTag: { fontSize: "12px", color: "#6366f1", marginLeft: "5px" },
  subtitle: { fontSize: "13px", color: "#94a3b8", margin: "4px 0 0 0" },
  counter: { fontSize: "14px", fontWeight: "600", color: "#6366f1" },

  progressBarBg: {
    height: "4px",
    background: "rgba(255,255,255,0.05)",
    borderRadius: "10px",
    marginBottom: "40px",
    overflow: "hidden"
  },
  progressBarFill: {
    height: "100%",
    background: "linear-gradient(90deg, #6366f1, #a855f7)",
    transition: "width 0.4s ease",
  },

  card: {
    background: "rgba(30, 41, 59, 0.5)",
    backdropFilter: "blur(20px)",
    borderRadius: "28px",
    padding: "40px",
    border: "1px solid rgba(255, 255, 255, 0.08)",
    boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.5)",
  },
  badge: {
    fontSize: "11px",
    textTransform: "uppercase",
    letterSpacing: "1px",
    color: "#818cf8",
    fontWeight: "700",
    marginBottom: "12px",
    display: "block"
  },
  questionText: {
    fontSize: "24px",
    lineHeight: "1.4",
    margin: "0 0 32px 0",
    fontWeight: "600",
  },
  optionsGrid: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "16px",
  },
  optionBtn: {
    all: "unset",
    display: "flex",
    alignItems: "center",
    padding: "18px 24px",
    background: "rgba(255,255,255,0.03)",
    border: "1px solid rgba(255,255,255,0.08)",
    borderRadius: "16px",
    cursor: "pointer",
    transition: "0.2s ease",
  },
  optionSelected: {
    background: "rgba(99, 102, 241, 0.1)",
    borderColor: "#6366f1",
  },
  radio: {
    width: "16px",
    height: "16px",
    border: "2px solid",
    borderRadius: "50%",
    marginRight: "15px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center"
  },
  radioInner: { width: "8px", height: "8px", background: "#6366f1", borderRadius: "50%" },

  footer: {
    marginTop: "40px",
    display: "flex",
    justifyContent: "space-between",
  },
  navBtn: {
    all: "unset",
    color: "#94a3b8",
    fontWeight: "600",
    cursor: "pointer",
    padding: "10px 20px"
  },
  nextBtn: {
    all: "unset",
    background: "#6366f1",
    padding: "12px 32px",
    borderRadius: "12px",
    fontWeight: "700",
    cursor: "pointer",
    boxShadow: "0 10px 15px -3px rgba(99, 102, 241, 0.3)",
  },

  /* Aesthetic Orbs */
  blob1: { position: "absolute", top: "10%", left: "10%", width: "300px", height: "300px", background: "#6366f1", filter: "blur(120px)", opacity: 0.1 },
  blob2: { position: "absolute", bottom: "10%", right: "10%", width: "300px", height: "300px", background: "#a855f7", filter: "blur(120px)", opacity: 0.1 },
};

export default App;
